logic [3:0] fsm_state, fsm_next;
logic       xorr_result;
always_ff @(posedge clk or posedge arst)
  if (arst) fsm_state <= 4'd0;
  else      fsm_state <= fsm_next;
always_comb
  if (fsm_state == 4'd10)
    fsm_next = xorr_result ? 4'd0 : fsm_state;
  else
    fsm_next = fsm_state;
